def gen(rng, size):
    cap = max(1, min(size, 1000))
    def mk():
        L = rng.randint(1, cap)
        if L == 1:
            return [rng.randint(0, 1)]
        return [1] + [rng.randint(0, 1) for _ in range(L - 1)]
    return [mk(), mk()]

