class Solution:
    def addNegabinary(self, arr1, arr2):
        def to_int(arr):
            val = 0
            for d in arr:
                val = val * (-2) + d
            return val
        total = to_int(arr1) + to_int(arr2)
        if total == 0:
            return [0]
        digits = []
        n = total
        while n != 0:
            rem = n % (-2)
            n //= (-2)
            if rem < 0:
                rem += 2
                n += 1
            digits.append(rem)
        return digits[::-1]

