class Solution:
    def addNegabinary(self, arr1, arr2):
        a = arr1[::-1]
        b = arr2[::-1]
        res = []
        carry = 0
        i = 0
        while i < len(a) or i < len(b) or carry != 0:
            total = carry
            if i < len(a):
                total += a[i]
            if i < len(b):
                total += b[i]
            res.append(total & 1)
            carry = -(total >> 1)
            i += 1
        while len(res) > 1 and res[-1] == 0:
            res.pop()
        return res[::-1]

