var addNegabinary = function(arr1, arr2) {
    const a = arr1.slice().reverse();
    const b = arr2.slice().reverse();
    const res = [];
    let carry = 0, i = 0;
    while (i < a.length || i < b.length || carry !== 0) {
        let total = carry;
        if (i < a.length) total += a[i];
        if (i < b.length) total += b[i];
        res.push(total & 1);
        carry = -(total >> 1);
        i++;
    }
    while (res.length > 1 && res[res.length - 1] === 0) res.pop();
    return res.reverse();
};
